import { useState } from "react";
import { NavBar } from "./NavBar";
import { Footer } from "./Footer";

import pattern from "../slike/pattern4.jpg";

import { useEffect } from "react";

export function Registracija(){

    const[ime,setIme]=useState("");
    const[prezime,setPrezime]=useState("");
    const[email,setEmail]=useState("");
    const[telefon,setTelefon]=useState("");
    const[adresa,setAdresa]=useState("");
    const[lozinkaHash,setLozinka]=useState("");
    const[potvrdaLozinke,setPotvrda]=useState("");
    const[datumRodjenja,setDatumRodjenja]=useState();
   const [gradovi, setGradovi] = useState([]);
const [idGrad, setGradId] = useState();

     useEffect(() => {
    fetch("http://localhost:8080/grad/all", {
      method: "GET",
      headers: {
        "Content-Type": "application/json",
      },
    })
      .then(response => response.json()) 
      .then(data => setGradovi(data.data.values))
      .catch(error => console.error("Greška prilikom učitavanja gradova:", error));
  }, []);



  const handleSubmit = async (e) => {
  e.preventDefault();

  if (lozinkaHash !== potvrdaLozinke) {
    alert("Lozinke se ne poklapaju!");
    return;
  }

  const userData = {
    ime,
    prezime,
    email,
    telefon,
    adresa,
    lozinkaHash,
    datumRodjenja,
    grad: { id: 1 } 
  };

  console.log("Šaljem podatke:", userData); 

  try {
    const response = await fetch("http://localhost:8080/guests/register", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(userData),
    });

    if (response.ok) {
      alert("Uspešno registrovani!");
    } else {
      const data = await response.json();
      console.error("Greška sa backendom:", data);
      alert(`Greška: ${data.data?.value || data.message || "Neuspešna registracija"}`);
    }
  } catch (error) {
    console.log("Greška", error);
    alert("Server nije dostupan.");
  }
};



return(
    <>
    <NavBar />
    <div style={{ backgroundImage: `url(${pattern})`,
    backgroundSize: "cover",   
    backgroundPosition: "center",
    minHeight: "100vh",         
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    flexDirection: "column"}}>
    <div className="forma">
        <form onSubmit={handleSubmit}>
        <span className="formaSpan">
            Unesite ime
            <input type="text" onChange={(e)=>setIme(e.target.value)} required/>
        </span>
        <span className="formaSpan"> 
            Unesite prezime
            <input type="text" onChange={(e)=>setPrezime(e.target.value)} required />
        </span>
        <span className="formaSpan">
            Unesite email
            <input type="email" onChange={(e)=>setEmail(e.target.value)} required />

        </span>

        <span className="formaSpan">
            Unesite lozinku
            <input type="password" onChange={(e)=>setLozinka(e.target.value)} required/>
        </span>
        <span className="formaSpan">
            Potvrdite lozinku
            <input type="password" onChange={(e)=>setPotvrda(e.target.value)} required/>
        </span>
        <span className="formaSpan">
            Unesite telefon
            <input type="text" onChange={(e)=>setTelefon(e.target.value)} required />
        </span>

        <span className="formaSpan">
            Unesite adresu
            <input type="text" onChange={(e)=>setAdresa(e.target.value)} required />
        </span>

        <span className="formaSpan">
            Unesite datum rodjenja
            <input type="date" onChange={(e)=>setDatumRodjenja(e.target.value)} required />
        </span>
        <span className="formaSpan">
  Unesite grad
  <select onChange={(e) => setGradId(e.target.value)} required>
    <option value="">-- Izaberite grad --</option>
    {gradovi && gradovi.map((grad) => (
      <option key={grad.idGrad} value={grad.idGrad}>
        {grad.name}
      </option>
    ))}
  </select>
</span>



       <button type="submit" className="btnNav" style={{marginTop:"20px",border: "none",fontSize:"18px",width:"160px",height:"50px"}}>Napravi nalog</button>


</form>

    </div>
    </div>
    <Footer />
    </>
)


}
